import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

const Profile = () => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        const fetchUser = async () => {
            try {
                const response = await axios.get('/api/auth/me', { withCredentials: true });
                setUser(response.data);
            } catch (err) {
                setError('⚠️ Failed to load user profile.');
            } finally {
                setLoading(false);
            }
        };
        fetchUser();
    }, []);

    if (loading) {
        return (
            <div className="flex justify-center items-center h-screen">
                <p className="text-gray-600 text-lg">Loading profile...</p>
            </div>
        );
    }

    if (error) {
        return (
            <div className="flex justify-center items-center h-screen">
                <p className="text-red-600 text-lg font-semibold">{error}</p>
            </div>
        );
    }

    if (!user) {
        return (
            <div className="flex justify-center items-center h-screen">
                <p className="text-gray-500 text-lg">No user data available.</p>
            </div>
        );
    }

    return (
        <div className="min-h-screen flex justify-center items-center bg-gradient-to-br from-green-100 to-blue-100 px-4">
            <div className="bg-white shadow-lg rounded-xl p-8 max-w-md w-full border border-gray-200">
                <h2 className="text-2xl font-bold text-blue-700 text-center mb-6">User Profile</h2>

                <div className="space-y-4 text-gray-700 text-lg">
                    <p><strong>Username:</strong> <span className="ml-2">{user.username || 'N/A'}</span></p>
                    <p><strong>Email:</strong> <span className="ml-2">{user.email || 'N/A'}</span></p>
                    <p><strong>Role:</strong>
                        <span className="ml-2 px-3 py-1 rounded-full text-sm font-medium bg-blue-100 text-blue-800">
              {user.role}
            </span>
                    </p>
                </div>

                <div className="mt-6 text-center">
                    <Link
                        to="/app/edit-profile"
                        className="inline-block bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-md transition"
                    >
                        Edit Profile
                    </Link>
                </div>
            </div>
        </div>
    );
};

export default Profile;
